     1→/* Blueprint.js Core Styles */
     2→@import "@blueprintjs/core/lib/css/blueprint.css";
     3→@import "@blueprintjs/icons/lib/css/blueprint-icons.css";
     4→@import "@blueprintjs/table/lib/css/table.css";
     5→@import "@blueprintjs/select/lib/css/blueprint-select.css";
     6→@import "@blueprintjs/datetime2/lib/css/blueprint-datetime2.css";
     7→
     8→/* Google Fonts */
     9→@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');
    10→
    11→/* Leaflet Map Styles */
    12→@import 'leaflet/dist/leaflet.css';
    13→
    14→/* =============================================================================
    15→   MMS DESIGN TOKENS
    16→   Unified design token system for Metro Mileage Management System
    17→   Version: 1.0.0 | Last Updated: 2025-12-28
    18→   ============================================================================= */
    19→
    20→:root {
    21→  /* =========================================================================
    22→     BRAND COLORS
    23→     Primary brand identity colors for MMS
    24→     ========================================================================= */
    25→  --mms-primary: #2563eb;           /* Primary brand blue */
    26→  --mms-primary-hover: #1d4ed8;     /* Primary hover state */
    27→  --mms-primary-light: #dbeafe;     /* Light background for primary */
    28→
    29→  /* =========================================================================
    30→     BACKGROUND COLORS
    31→     Surface and container backgrounds
    32→     ========================================================================= */
    33→  --mms-bg-app: #f8fafc;            /* Main app background */
    34→  --mms-bg-card: #ffffff;           /* Card/panel background */
    35→  --mms-bg-surface: #f5f8fa;        /* Elevated surfaces, legends, headers */
    36→  --mms-bg-hover: #e1e8ed;          /* Hover state background */
    37→  --mms-bg-selected: #e1e8ed;       /* Selected item background */
    38→
    39→  /* =========================================================================
    40→     TEXT COLORS
    41→     Typography color hierarchy
    42→     ========================================================================= */
    43→  --mms-text-primary: #182026;      /* Primary text - headings, important content */
    44→  --mms-text-secondary: #5c7080;    /* Secondary text - labels, descriptions */
    45→  --mms-text-muted: #8a9ba8;        /* Muted text - hints, timestamps, metadata */
    46→  --mms-text-disabled: #a6b1bb;     /* Disabled state text */
    47→
    48→  /* =========================================================================
    49→     BORDER COLORS
    50→     Borders and dividers
    51→     ========================================================================= */
    52→  --mms-border-default: #e1e8ed;    /* Default borders - cards, dividers */
    53→  --mms-border-light: #f0f0f0;      /* Light borders - table rows, subtle dividers */
    54→  --mms-border-focus: #2563eb;      /* Focus ring color */
    55→
    56→  /* =========================================================================
    57→     STATUS COLORS
    58→     Semantic colors for train/equipment status
    59→     ========================================================================= */
    60→  --mms-status-available: #22c55e;   /* Available/fit trains - green */
    61→  --mms-status-in-service: #3b82f6;  /* In service trains - blue */
    62→  --mms-status-maintenance: #ef4444; /* In maintenance - red */
    63→  --mms-status-depot: #6b7280;       /* Depot marker color - gray */
    64→
    65→  /* =========================================================================
    66→     VARIANCE TRAFFIC LIGHT
    67→     KPI variance indicators (from EN 15380 guidelines)
    68→     ========================================================================= */
    69→  --mms-variance-green: #22c55e;     /* Target met (≤10% variance) */
    70→  --mms-variance-yellow: #eab308;    /* Attention needed (10-15% variance) */
    71→  --mms-variance-red: #ef4444;       /* Critical variance (>15%) */
    72→
    73→  /* =========================================================================
    74→     MAINTENANCE TYPE COLORS
    75→     Color coding for different maintenance types
    76→     ========================================================================= */
    77→  --mms-maint-pm1: #10B981;          /* PM1 - Preventive Minor (emerald) */
    78→  --mms-maint-pm1-bg: #93c5fd;       /* PM1 background for Gantt */
    79→  --mms-maint-pm1-text: #1e40af;     /* PM1 text on light bg */
    80→  --mms-maint-pm2: #3B82F6;          /* PM2 - Preventive Major (blue) */
    81→  --mms-maint-pm3: #F59E0B;          /* PM3/HM - Heavy Maintenance (amber) */
    82→  --mms-maint-hm: #F59E0B;           /* HM - Heavy Maintenance (alias) */
    83→  --mms-maint-hm-bg: #f87171;        /* HM background */
    84→  --mms-maint-overhaul: #EF4444;     /* OVH - Overhaul (red) */
    85→  --mms-maint-ovh: #EF4444;          /* OVH alias */
    86→  --mms-maint-ovh-bg: #c084fc;       /* OVH background (purple) */
    87→
    88→  /* =========================================================================
    89→     CAPACITY/UTILIZATION HEATMAP
    90→     Colors for depot capacity visualization
    91→     ========================================================================= */
    92→  --mms-capacity-empty: #f9fafb;     /* 0% utilization */
    93→  --mms-capacity-low: #dcfce7;       /* <50% utilization */
    94→  --mms-capacity-medium: #bbf7d0;    /* 50-70% utilization */
    95→  --mms-capacity-high: #fbbf24;      /* 70-90% utilization */
    96→  --mms-capacity-critical: #f87171;  /* >90% utilization */
    97→  --mms-capacity-full: #ef4444;      /* 100% utilization */
    98→
    99→  /* =========================================================================
   100→     INTERACTIVE STATES
   101→     Drag, drop, and validation states
   102→     ========================================================================= */
   103→  --mms-valid-drop-bg: #d1fae5;      /* Valid drop zone background */
   104→  --mms-valid-drop-border: #10b981;  /* Valid drop zone border */
   105→  --mms-invalid-drop-border: #ef4444;/* Invalid drop zone border */
   106→  --mms-today-highlight: #eff6ff;    /* Today column highlight */
   107→  --mms-today-line: #2563eb;         /* Today indicator line */
   108→  --mms-weekend-bg: #f9fafb;         /* Weekend column background */
   109→
   110→  /* =========================================================================
   111→     SPECIAL COLORS
   112→     Miscellaneous colors for specific UI elements
   113→     ========================================================================= */
   114→  --mms-epic-tag: #e9d5ff;           /* Epic tag background (purple light) */
   115→  --mms-epic-tag-text: #7e22ce;      /* Epic tag text (purple dark) */
   116→  --mms-toast-bg: #30404d;           /* Toast/snackbar background */
   117→
   118→  /* =========================================================================
   119→     SPACING SCALE
   120→     Consistent spacing based on 4px grid
   121→     ========================================================================= */
   122→  --mms-space-xs: 4px;
   123→  --mms-space-sm: 8px;
   124→  --mms-space-md: 16px;
   125→  --mms-space-lg: 24px;
   126→  --mms-space-xl: 32px;
   127→  --mms-space-2xl: 48px;
   128→
   129→  /* =========================================================================
   130→     BORDER RADIUS
   131→     Consistent corner rounding
   132→     ========================================================================= */
   133→  --mms-radius-sm: 4px;
   134→  --mms-radius-md: 8px;
   135→  --mms-radius-lg: 12px;
   136→  --mms-radius-full: 9999px;
   137→
   138→  /* =========================================================================
   139→     TYPOGRAPHY
   140→     Font sizes and weights
   141→     ========================================================================= */
   142→  --mms-font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
   143→  --mms-font-mono: 'JetBrains Mono', 'Monaco', 'Menlo', monospace;
   144→
   145→  --mms-text-xs: 11px;
   146→  --mms-text-sm: 12px;
   147→  --mms-text-base: 14px;
   148→  --mms-text-lg: 18px;
   149→  --mms-text-xl: 20px;
   150→  --mms-text-2xl: 24px;
   151→  --mms-text-3xl: 28px;
   152→  --mms-text-4xl: 32px;
   153→
   154→  --mms-font-normal: 400;
   155→  --mms-font-medium: 500;
   156→  --mms-font-semibold: 600;
   157→  --mms-font-bold: 700;
   158→
   159→  /* =========================================================================
   160→     SHADOWS
   161→     Consistent elevation shadows
   162→     ========================================================================= */
   163→  --mms-shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.05);
   164→  --mms-shadow-md: 0 4px 6px rgba(0, 0, 0, 0.1);
   165→  --mms-shadow-lg: 0 4px 8px rgba(0, 0, 0, 0.2);
   166→
   167→  /* =========================================================================
   168→     TRANSITIONS
   169→     Animation timing
   170→     ========================================================================= */
   171→  --mms-transition-fast: 100ms ease-in-out;
   172→  --mms-transition-normal: 200ms ease-in-out;
   173→  --mms-transition-slow: 300ms ease-in-out;
   174→}
   175→
   176→/* =============================================================================
   177→   DARK MODE THEME
   178→   Override CSS variables when .bp5-dark class is applied to body
   179→   Blueprint.js v6 uses .bp5-dark for dark mode styling
   180→   ============================================================================= */
   181→
   182→.bp5-dark {
   183→  /* =========================================================================
   184→     BACKGROUND COLORS - Dark Mode
   185→     ========================================================================= */
   186→  --mms-bg-app: #1a1a2e;            /* Main app background - deep navy */
   187→  --mms-bg-card: #16213e;           /* Card/panel background - dark blue */
   188→  --mms-bg-surface: #1f2937;        /* Elevated surfaces - slate */
   189→  --mms-bg-hover: #374151;          /* Hover state background */
   190→  --mms-bg-selected: rgba(37, 99, 235, 0.2); /* Selected item - blue tint */
   191→
   192→  /* =========================================================================
   193→     TEXT COLORS - Dark Mode
   194→     ========================================================================= */
   195→  --mms-text-primary: #f9fafb;      /* Primary text - near white */
   196→  --mms-text-secondary: #d1d5db;    /* Secondary text - light gray */
   197→  --mms-text-muted: #9ca3af;        /* Muted text - medium gray */
   198→  --mms-text-disabled: #6b7280;     /* Disabled state text */
   199→
   200→  /* =========================================================================
   201→     BORDER COLORS - Dark Mode
   202→     ========================================================================= */
   203→  --mms-border-default: #374151;    /* Default borders - dark gray */
   204→  --mms-border-light: #4b5563;      /* Light borders */
   205→  --mms-border-focus: #3b82f6;      /* Focus ring - blue */
   206→
   207→  /* =========================================================================
   208→     INTERACTIVE STATES - Dark Mode
   209→     ========================================================================= */
   210→  --mms-today-highlight: rgba(37, 99, 235, 0.15); /* Today column - blue tint */
   211→  --mms-weekend-bg: #111827;        /* Weekend column - darker */
   212→
   213→  /* =========================================================================
   214→     CAPACITY HEATMAP - Dark Mode
   215→     Adjusted for better visibility on dark backgrounds
   216→     ========================================================================= */
   217→  --mms-capacity-empty: #1f2937;    /* 0% utilization */
   218→  --mms-capacity-low: #064e3b;      /* <50% - dark green */
   219→  --mms-capacity-medium: #065f46;   /* 50-70% - medium green */
   220→
   221→  /* =========================================================================
   222→     SPECIAL COLORS - Dark Mode
   223→     ========================================================================= */
   224→  --mms-toast-bg: #1f2937;          /* Toast background */
   225→  --mms-epic-tag: #581c87;          /* Epic tag - dark purple */
   226→  --mms-epic-tag-text: #e9d5ff;     /* Epic tag text - light purple */
   227→
   228→  /* =========================================================================
   229→     SHADOWS - Dark Mode
   230→     More subtle shadows for dark theme
   231→     ========================================================================= */
   232→  --mms-shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.3);
   233→  --mms-shadow-md: 0 4px 6px rgba(0, 0, 0, 0.4);
   234→  --mms-shadow-lg: 0 4px 8px rgba(0, 0, 0, 0.5);
   235→}
   236→
   237→/* =============================================================================
   238→   BLUEPRINT.JS DARK MODE OVERRIDES
   239→   Force Blueprint v6 components to use MMS dark theme tokens
   240→   Note: Blueprint v6 uses bp6-* classes for components but bp5-dark for theme
   241→   ============================================================================= */
   242→
   243→/* Cards - Primary component for dark mode */
   244→.bp5-dark .bp6-card,
   245→.bp5-dark .bp5-card {
   246→  background-color: var(--mms-bg-card);
   247→  color: var(--mms-text-primary);
   248→}
   249→
   250→/* Navbar */
   251→.bp5-dark .bp6-navbar,
   252→.bp5-dark .bp5-navbar {
   253→  background-color: var(--mms-bg-card);
   254→}
   255→
   256→/* Buttons */
   257→.bp5-dark .bp6-button.bp6-minimal,
   258→.bp5-dark .bp5-button.bp5-minimal {
   259→  color: var(--mms-text-primary);
   260→}
   261→
   262→.bp5-dark .bp6-button.bp6-minimal:hover,
   263→.bp5-dark .bp5-button.bp5-minimal:hover {
   264→  background-color: var(--mms-bg-hover);
   265→}
   266→
   267→/* Callouts */
   268→.bp5-dark .bp6-callout,
   269→.bp5-dark .bp5-callout {
   270→  background-color: var(--mms-bg-surface);
   271→}
   272→
   273→/* Inputs */
   274→.bp5-dark .bp6-input,
   275→.bp5-dark .bp6-input-group .bp6-input,
   276→.bp5-dark .bp5-input,
   277→.bp5-dark .bp5-input-group .bp5-input {
   278→  background-color: var(--mms-bg-surface);
   279→  color: var(--mms-text-primary);
   280→}
   281→
   282→/* Menus */
   283→.bp5-dark .bp6-menu,
   284→.bp5-dark .bp5-menu {
   285→  background-color: var(--mms-bg-card);
   286→}
   287→
   288→/* Popovers */
   289→.bp5-dark .bp6-popover .bp6-popover-content,
   290→.bp5-dark .bp5-popover .bp5-popover-content {
   291→  background-color: var(--mms-bg-card);
   292→}
   293→
   294→/* Dialogs */
   295→.bp5-dark .bp6-dialog,
   296→.bp5-dark .bp5-dialog {
   297→  background-color: var(--mms-bg-card);
   298→}
   299→
   300→/* Tables */
   301→.bp5-dark .bp6-table-container,
   302→.bp5-dark .bp5-table-container {
   303→  background-color: var(--mms-bg-card);
   304→}
   305→
   306→/* Tags - ensure readable in dark mode */
   307→.bp5-dark .bp6-tag.bp6-minimal,
   308→.bp5-dark .bp5-tag.bp5-minimal {
   309→  background-color: var(--mms-bg-hover);
   310→}
   311→
   312→/* Progress bars */
   313→.bp5-dark .bp6-progress-bar,
   314→.bp5-dark .bp5-progress-bar {
   315→  background-color: var(--mms-bg-hover);
   316→}
   317→
   318→/* =============================================================================
   319→   BASE STYLES
   320→   ============================================================================= */
   321→
   322→body {
   323→  font-family: var(--mms-font-family);
   324→  margin: 0;
   325→  padding: 0;
   326→  background-color: var(--mms-bg-app);
   327→  color: var(--mms-text-primary);
   328→}
   329→
   330→/* Railway Domain Typography */
   331→.train-id {
   332→  font-family: var(--mms-font-mono);
   333→  font-weight: var(--mms-font-semibold);
   334→}
   335→
   336→.km-value {
   337→  font-family: var(--mms-font-mono);
   338→  font-variant-numeric: tabular-nums;
   339→}
   340→
   341→/* Custom scrollbar styling */
   342→::-webkit-scrollbar {
   343→  width: var(--mms-space-sm);
   344→  height: var(--mms-space-sm);
   345→}
   346→
   347→::-webkit-scrollbar-track {
   348→  background: var(--mms-bg-surface);
   349→}
   350→
   351→::-webkit-scrollbar-thumb {
   352→  background: var(--mms-text-muted);
   353→  border-radius: var(--mms-radius-sm);
   354→}
   355→
   356→::-webkit-scrollbar-thumb:hover {
   357→  background: var(--mms-text-secondary);
   358→}
   359→
   360→/* Map container */
   361→.leaflet-container {
   362→  background-color: var(--mms-bg-app);
   363→}
   364→
   365→/* MMS Custom Button Intents */
   366→.bp6-button.mms-available {
   367→  background-color: var(--mms-status-available) !important;
   368→  color: white !important;
   369→}
   370→
   371→.bp6-button.mms-maintenance {
   372→  background-color: var(--mms-status-maintenance) !important;
   373→  color: white !important;
   374→}
   375→
   376→/* Status Tags */
   377→.mms-status-available {
   378→  background-color: var(--mms-status-available);
   379→  color: white;
   380→}
   381→
   382→.mms-status-in-service {
   383→  background-color: var(--mms-status-in-service);
   384→  color: white;
   385→}
   386→
   387→.mms-status-maintenance {
   388→  background-color: var(--mms-status-maintenance);
   389→  color: white;
   390→}
   391→
   392→/* Variance Tags */
   393→.mms-variance-green {
   394→  background-color: var(--mms-variance-green);
   395→  color: white;
   396→}
   397→
   398→.mms-variance-yellow {
   399→  background-color: var(--mms-variance-yellow);
   400→  color: black;
   401→}
   402→
   403→.mms-variance-red {
   404→  background-color: var(--mms-variance-red);
   405→  color: white;
   406→}
   407→
   408→/* Maintenance Type Tags */
   409→.mms-maint-pm1 {
   410→  background-color: var(--mms-maint-pm1);
   411→  color: white;
   412→}
   413→
   414→.mms-maint-pm2 {
   415→  background-color: var(--mms-maint-pm2);
   416→  color: white;
   417→}
   418→
   419→.mms-maint-pm3 {
   420→  background-color: var(--mms-maint-pm3);
   421→  color: black;
   422→}
   423→
   424→.mms-maint-overhaul {
   425→  background-color: var(--mms-maint-overhaul);
   426→  color: white;
   427→}
   428→
   429→/* =============================================================================
   430→   LAYOUT UTILITIES
   431→   ============================================================================= */
   432→
   433→/* Grid layout helpers */
   434→.mms-grid-4 {
   435→  display: grid;
   436→  grid-template-columns: repeat(4, 1fr);
   437→  gap: var(--mms-space-md);
   438→}
   439→
   440→.mms-grid-3 {
   441→  display: grid;
   442→  grid-template-columns: repeat(3, 1fr);
   443→  gap: var(--mms-space-md);
   444→}
   445→
   446→.mms-grid-2 {
   447→  display: grid;
   448→  grid-template-columns: repeat(2, 1fr);
   449→  gap: var(--mms-space-md);
   450→}
   451→
   452→@media (max-width: 1200px) {
   453→  .mms-grid-4 {
   454→    grid-template-columns: repeat(2, 1fr);
   455→  }
   456→}
   457→
   458→@media (max-width: 768px) {
   459→  .mms-grid-4,
   460→  .mms-grid-3,
   461→  .mms-grid-2 {
   462→    grid-template-columns: 1fr;
   463→  }
   464→}
   465→
   466→/* App Layout */
   467→.mms-app-container {
   468→  min-height: 100vh;
   469→  background-color: var(--mms-bg-app);
   470→}
   471→
   472→.mms-main-content {
   473→  max-width: 1400px;
   474→  margin: 0 auto;
   475→  padding: var(--mms-space-lg);
   476→}
   477→
   478→/* Card styling extensions */
   479→.mms-kpi-card {
   480→  border-left: 4px solid var(--mms-primary);
   481→}
   482→
   483→.mms-kpi-card.available {
   484→  border-left-color: var(--mms-status-available);
   485→}
   486→
   487→.mms-kpi-card.maintenance {
   488→  border-left-color: var(--mms-status-maintenance);
   489→}
   490→
   491→.mms-kpi-card.variance-green {
   492→  border-left-color: var(--mms-variance-green);
   493→}
   494→
   495→.mms-kpi-card.variance-yellow {
   496→  border-left-color: var(--mms-variance-yellow);
   497→}
   498→
   499→.mms-kpi-card.variance-red {
   500→  border-left-color: var(--mms-variance-red);
   501→}
