/* Blueprint.js Core Styles */
@import "@blueprintjs/core/lib/css/blueprint.css";
@import "@blueprintjs/icons/lib/css/blueprint-icons.css";
@import "@blueprintjs/table/lib/css/table.css";
@import "@blueprintjs/select/lib/css/blueprint-select.css";
@import "@blueprintjs/datetime2/lib/css/blueprint-datetime2.css";

/* Google Fonts */
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=JetBrains+Mono:wght@400;500&display=swap');

/* Leaflet Map Styles */
@import 'leaflet/dist/leaflet.css';

/* =============================================================================
   MMS DESIGN TOKENS
   Unified design token system for Metro Mileage Management System
   Version: 1.0.0 | Last Updated: 2025-12-28
   ============================================================================= */

:root {
  /* =========================================================================
     BRAND COLORS
     Primary brand identity colors for MMS
     ========================================================================= */
  --mms-primary: #2563eb;           /* Primary brand blue */
  --mms-primary-hover: #1d4ed8;     /* Primary hover state */
  --mms-primary-light: #dbeafe;     /* Light background for primary */

  /* =========================================================================
     BACKGROUND COLORS
     Surface and container backgrounds
     ========================================================================= */
  --mms-bg-app: #f8fafc;            /* Main app background */
  --mms-bg-card: #ffffff;           /* Card/panel background */
  --mms-bg-surface: #f5f8fa;        /* Elevated surfaces, legends, headers */
  --mms-bg-hover: #e1e8ed;          /* Hover state background */
  --mms-bg-selected: #e1e8ed;       /* Selected item background */

  /* =========================================================================
     TEXT COLORS
     Typography color hierarchy
     ========================================================================= */
  --mms-text-primary: #182026;      /* Primary text - headings, important content */
  --mms-text-secondary: #5c7080;    /* Secondary text - labels, descriptions */
  --mms-text-muted: #8a9ba8;        /* Muted text - hints, timestamps, metadata */
  --mms-text-disabled: #a6b1bb;     /* Disabled state text */

  /* =========================================================================
     BORDER COLORS
     Borders and dividers
     ========================================================================= */
  --mms-border-default: #e1e8ed;    /* Default borders - cards, dividers */
  --mms-border-light: #f0f0f0;      /* Light borders - table rows, subtle dividers */
  --mms-border-focus: #2563eb;      /* Focus ring color */

  /* =========================================================================
     STATUS COLORS
     Semantic colors for train/equipment status
     ========================================================================= */
  --mms-status-available: #22c55e;   /* Available/fit trains - green */
  --mms-status-in-service: #3b82f6;  /* In service trains - blue */
  --mms-status-maintenance: #ef4444; /* In maintenance - red */
  --mms-status-depot: #6b7280;       /* Depot marker color - gray */

  /* =========================================================================
     VARIANCE TRAFFIC LIGHT
     KPI variance indicators (from EN 15380 guidelines)
     ========================================================================= */
  --mms-variance-green: #22c55e;     /* Target met (≤10% variance) */
  --mms-variance-yellow: #eab308;    /* Attention needed (10-15% variance) */
  --mms-variance-red: #ef4444;       /* Critical variance (>15%) */

  /* =========================================================================
     MAINTENANCE TYPE COLORS
     Color coding for different maintenance types
     ========================================================================= */
  --mms-maint-pm1: #10B981;          /* PM1 - Preventive Minor (emerald) */
  --mms-maint-pm1-bg: #93c5fd;       /* PM1 background for Gantt */
  --mms-maint-pm1-text: #1e40af;     /* PM1 text on light bg */
  --mms-maint-pm2: #3B82F6;          /* PM2 - Preventive Major (blue) */
  --mms-maint-pm3: #F59E0B;          /* PM3/HM - Heavy Maintenance (amber) */
  --mms-maint-hm: #F59E0B;           /* HM - Heavy Maintenance (alias) */
  --mms-maint-hm-bg: #f87171;        /* HM background */
  --mms-maint-overhaul: #EF4444;     /* OVH - Overhaul (red) */
  --mms-maint-ovh: #EF4444;          /* OVH alias */
  --mms-maint-ovh-bg: #c084fc;       /* OVH background (purple) */

  /* =========================================================================
     CAPACITY/UTILIZATION HEATMAP
     Colors for depot capacity visualization
     ========================================================================= */
  --mms-capacity-empty: #f9fafb;     /* 0% utilization */
  --mms-capacity-low: #dcfce7;       /* <50% utilization */
  --mms-capacity-medium: #bbf7d0;    /* 50-70% utilization */
  --mms-capacity-high: #fbbf24;      /* 70-90% utilization */
  --mms-capacity-critical: #f87171;  /* >90% utilization */
  --mms-capacity-full: #ef4444;      /* 100% utilization */

  /* =========================================================================
     INTERACTIVE STATES
     Drag, drop, and validation states
     ========================================================================= */
  --mms-valid-drop-bg: #d1fae5;      /* Valid drop zone background */
  --mms-valid-drop-border: #10b981;  /* Valid drop zone border */
  --mms-invalid-drop-border: #ef4444;/* Invalid drop zone border */
  --mms-today-highlight: #eff6ff;    /* Today column highlight */
  --mms-today-line: #2563eb;         /* Today indicator line */
  --mms-weekend-bg: #f9fafb;         /* Weekend column background */

  /* =========================================================================
     SPECIAL COLORS
     Miscellaneous colors for specific UI elements
     ========================================================================= */
  --mms-epic-tag: #e9d5ff;           /* Epic tag background (purple light) */
  --mms-epic-tag-text: #7e22ce;      /* Epic tag text (purple dark) */
  --mms-toast-bg: #30404d;           /* Toast/snackbar background */

  /* =========================================================================
     SPACING SCALE
     Consistent spacing based on 4px grid
     ========================================================================= */
  --mms-space-xs: 4px;
  --mms-space-sm: 8px;
  --mms-space-md: 16px;
  --mms-space-lg: 24px;
  --mms-space-xl: 32px;
  --mms-space-2xl: 48px;

  /* =========================================================================
     BORDER RADIUS
     Consistent corner rounding
     ========================================================================= */
  --mms-radius-sm: 4px;
  --mms-radius-md: 8px;
  --mms-radius-lg: 12px;
  --mms-radius-full: 9999px;

  /* =========================================================================
     TYPOGRAPHY
     Font sizes and weights
     ========================================================================= */
  --mms-font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  --mms-font-mono: 'JetBrains Mono', 'Monaco', 'Menlo', monospace;

  --mms-text-xs: 11px;
  --mms-text-sm: 12px;
  --mms-text-base: 14px;
  --mms-text-lg: 18px;
  --mms-text-xl: 20px;
  --mms-text-2xl: 24px;
  --mms-text-3xl: 28px;
  --mms-text-4xl: 32px;

  --mms-font-normal: 400;
  --mms-font-medium: 500;
  --mms-font-semibold: 600;
  --mms-font-bold: 700;

  /* =========================================================================
     SHADOWS
     Consistent elevation shadows
     ========================================================================= */
  --mms-shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.05);
  --mms-shadow-md: 0 4px 6px rgba(0, 0, 0, 0.1);
  --mms-shadow-lg: 0 4px 8px rgba(0, 0, 0, 0.2);

  /* =========================================================================
     TRANSITIONS
     Animation timing
     ========================================================================= */
  --mms-transition-fast: 100ms ease-in-out;
  --mms-transition-normal: 200ms ease-in-out;
  --mms-transition-slow: 300ms ease-in-out;
}

/* =============================================================================
   DARK MODE THEME
   Override CSS variables when .bp5-dark class is applied to body
   Blueprint.js v6 uses .bp5-dark for dark mode styling
   ============================================================================= */

.bp5-dark {
  /* =========================================================================
     BACKGROUND COLORS - Dark Mode
     ========================================================================= */
  --mms-bg-app: #1a1a2e;            /* Main app background - deep navy */
  --mms-bg-card: #16213e;           /* Card/panel background - dark blue */
  --mms-bg-surface: #1f2937;        /* Elevated surfaces - slate */
  --mms-bg-hover: #374151;          /* Hover state background */
  --mms-bg-selected: rgba(37, 99, 235, 0.2); /* Selected item - blue tint */

  /* =========================================================================
     TEXT COLORS - Dark Mode
     ========================================================================= */
  --mms-text-primary: #f9fafb;      /* Primary text - near white */
  --mms-text-secondary: #d1d5db;    /* Secondary text - light gray */
  --mms-text-muted: #9ca3af;        /* Muted text - medium gray */
  --mms-text-disabled: #6b7280;     /* Disabled state text */

  /* =========================================================================
     BORDER COLORS - Dark Mode
     ========================================================================= */
  --mms-border-default: #374151;    /* Default borders - dark gray */
  --mms-border-light: #4b5563;      /* Light borders */
  --mms-border-focus: #3b82f6;      /* Focus ring - blue */

  /* =========================================================================
     INTERACTIVE STATES - Dark Mode
     ========================================================================= */
  --mms-today-highlight: rgba(37, 99, 235, 0.15); /* Today column - blue tint */
  --mms-weekend-bg: #111827;        /* Weekend column - darker */

  /* =========================================================================
     CAPACITY HEATMAP - Dark Mode
     Adjusted for better visibility on dark backgrounds
     ========================================================================= */
  --mms-capacity-empty: #1f2937;    /* 0% utilization */
  --mms-capacity-low: #064e3b;      /* <50% - dark green */
  --mms-capacity-medium: #065f46;   /* 50-70% - medium green */

  /* =========================================================================
     SPECIAL COLORS - Dark Mode
     ========================================================================= */
  --mms-toast-bg: #1f2937;          /* Toast background */
  --mms-epic-tag: #581c87;          /* Epic tag - dark purple */
  --mms-epic-tag-text: #e9d5ff;     /* Epic tag text - light purple */

  /* =========================================================================
     SHADOWS - Dark Mode
     More subtle shadows for dark theme
     ========================================================================= */
  --mms-shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.3);
  --mms-shadow-md: 0 4px 6px rgba(0, 0, 0, 0.4);
  --mms-shadow-lg: 0 4px 8px rgba(0, 0, 0, 0.5);
}

/* =============================================================================
   BLUEPRINT.JS DARK MODE OVERRIDES
   Force Blueprint v6 components to use MMS dark theme tokens
   Note: Blueprint v6 uses bp6-* classes for components but bp5-dark for theme
   ============================================================================= */

/* Cards - Primary component for dark mode */
.bp5-dark .bp6-card,
.bp5-dark .bp5-card {
  background-color: var(--mms-bg-card);
  color: var(--mms-text-primary);
}

/* Navbar */
.bp5-dark .bp6-navbar,
.bp5-dark .bp5-navbar {
  background-color: var(--mms-bg-card);
}

/* Buttons */
.bp5-dark .bp6-button.bp6-minimal,
.bp5-dark .bp5-button.bp5-minimal {
  color: var(--mms-text-primary);
}

.bp5-dark .bp6-button.bp6-minimal:hover,
.bp5-dark .bp5-button.bp5-minimal:hover {
  background-color: var(--mms-bg-hover);
}

/* Callouts */
.bp5-dark .bp6-callout,
.bp5-dark .bp5-callout {
  background-color: var(--mms-bg-surface);
}

/* Inputs */
.bp5-dark .bp6-input,
.bp5-dark .bp6-input-group .bp6-input,
.bp5-dark .bp5-input,
.bp5-dark .bp5-input-group .bp5-input {
  background-color: var(--mms-bg-surface);
  color: var(--mms-text-primary);
}

/* Menus */
.bp5-dark .bp6-menu,
.bp5-dark .bp5-menu {
  background-color: var(--mms-bg-card);
}

/* Popovers */
.bp5-dark .bp6-popover .bp6-popover-content,
.bp5-dark .bp5-popover .bp5-popover-content {
  background-color: var(--mms-bg-card);
}

/* Dialogs */
.bp5-dark .bp6-dialog,
.bp5-dark .bp5-dialog {
  background-color: var(--mms-bg-card);
}

/* Tables */
.bp5-dark .bp6-table-container,
.bp5-dark .bp5-table-container {
  background-color: var(--mms-bg-card);
}

/* Tags - ensure readable in dark mode */
.bp5-dark .bp6-tag.bp6-minimal,
.bp5-dark .bp5-tag.bp5-minimal {
  background-color: var(--mms-bg-hover);
}

/* Progress bars */
.bp5-dark .bp6-progress-bar,
.bp5-dark .bp5-progress-bar {
  background-color: var(--mms-bg-hover);
}

/* =============================================================================
   BASE STYLES
   ============================================================================= */

body {
  font-family: var(--mms-font-family);
  margin: 0;
  padding: 0;
  background-color: var(--mms-bg-app);
  color: var(--mms-text-primary);
}

/* Railway Domain Typography */
.train-id {
  font-family: var(--mms-font-mono);
  font-weight: var(--mms-font-semibold);
}

.km-value {
  font-family: var(--mms-font-mono);
  font-variant-numeric: tabular-nums;
}

/* Custom scrollbar styling */
::-webkit-scrollbar {
  width: var(--mms-space-sm);
  height: var(--mms-space-sm);
}

::-webkit-scrollbar-track {
  background: var(--mms-bg-surface);
}

::-webkit-scrollbar-thumb {
  background: var(--mms-text-muted);
  border-radius: var(--mms-radius-sm);
}

::-webkit-scrollbar-thumb:hover {
  background: var(--mms-text-secondary);
}

/* Map container */
.leaflet-container {
  background-color: var(--mms-bg-app);
}

/* MMS Custom Button Intents */
.bp6-button.mms-available {
  background-color: var(--mms-status-available) !important;
  color: white !important;
}

.bp6-button.mms-maintenance {
  background-color: var(--mms-status-maintenance) !important;
  color: white !important;
}

/* Status Tags */
.mms-status-available {
  background-color: var(--mms-status-available);
  color: white;
}

.mms-status-in-service {
  background-color: var(--mms-status-in-service);
  color: white;
}

.mms-status-maintenance {
  background-color: var(--mms-status-maintenance);
  color: white;
}

/* Variance Tags */
.mms-variance-green {
  background-color: var(--mms-variance-green);
  color: white;
}

.mms-variance-yellow {
  background-color: var(--mms-variance-yellow);
  color: black;
}

.mms-variance-red {
  background-color: var(--mms-variance-red);
  color: white;
}

/* Maintenance Type Tags */
.mms-maint-pm1 {
  background-color: var(--mms-maint-pm1);
  color: white;
}

.mms-maint-pm2 {
  background-color: var(--mms-maint-pm2);
  color: white;
}

.mms-maint-pm3 {
  background-color: var(--mms-maint-pm3);
  color: black;
}

.mms-maint-overhaul {
  background-color: var(--mms-maint-overhaul);
  color: white;
}

/* =============================================================================
   LAYOUT UTILITIES
   ============================================================================= */

/* Grid layout helpers */
.mms-grid-4 {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: var(--mms-space-md);
}

.mms-grid-3 {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--mms-space-md);
}

.mms-grid-2 {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--mms-space-md);
}

@media (max-width: 1200px) {
  .mms-grid-4 {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 768px) {
  .mms-grid-4,
  .mms-grid-3,
  .mms-grid-2 {
    grid-template-columns: 1fr;
  }
}

/* App Layout */
.mms-app-container {
  min-height: 100vh;
  background-color: var(--mms-bg-app);
}

.mms-main-content {
  max-width: 1400px;
  margin: 0 auto;
  padding: var(--mms-space-lg);
}

/* Card styling extensions */
.mms-kpi-card {
  border-left: 4px solid var(--mms-primary);
}

.mms-kpi-card.available {
  border-left-color: var(--mms-status-available);
}

.mms-kpi-card.maintenance {
  border-left-color: var(--mms-status-maintenance);
}

.mms-kpi-card.variance-green {
  border-left-color: var(--mms-variance-green);
}

.mms-kpi-card.variance-yellow {
  border-left-color: var(--mms-variance-yellow);
}

.mms-kpi-card.variance-red {
  border-left-color: var(--mms-variance-red);
}

import { Card, Elevation } from '@blueprintjs/core';
import { DashboardKPIs, DepotCapacityCards, MaintenanceAlerts } from '@/components/dashboard';

export default function Home() {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--mms-space-lg)' }}>
      <Card elevation={Elevation.ONE} style={{ padding: 'var(--mms-space-lg)' }}>
        <h1 style={{ margin: 0, fontSize: 'var(--mms-text-2xl)', fontWeight: 'var(--mms-font-bold)', color: 'var(--mms-text-primary)' }}>
          MMS Dashboard
        </h1>
        <p style={{ marginTop: 'var(--mms-space-sm)', color: 'var(--mms-text-secondary)' }}>
          Railway Fleet Mileage Management System - Demo Version
        </p>
      </Card>

      {/* Fleet Summary KPIs - Story 2.1 */}
      <section>
        <h2 style={{ fontSize: 'var(--mms-text-lg)', fontWeight: 'var(--mms-font-semibold)', color: 'var(--mms-text-secondary)', marginBottom: 'var(--mms-space-md)' }}>Fleet Overview</h2>
        <DashboardKPIs />
      </section>

      {/* Depot Capacity Cards - Story 2.3 */}
      <section>
        <h2 style={{ fontSize: 'var(--mms-text-lg)', fontWeight: 'var(--mms-font-semibold)', color: 'var(--mms-text-secondary)', marginBottom: 'var(--mms-space-md)' }}>Depot Capacity</h2>
        <DepotCapacityCards />
      </section>

      {/* Maintenance Alerts - Story 2.4 */}
      <section>
        <h2 style={{ fontSize: 'var(--mms-text-lg)', fontWeight: 'var(--mms-font-semibold)', color: 'var(--mms-text-secondary)', marginBottom: 'var(--mms-space-md)' }}>Maintenance Alerts</h2>
        <MaintenanceAlerts />
      </section>
    </div>
  );
}

