'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Callout, Intent, IconName } from '@blueprintjs/core';
import { KPICard } from './KPICard';
import { dashboardApi, DashboardSummary } from '@/lib/api';

/**
 * Dashboard KPIs Component
 *
 * Displays the four main fleet KPIs:
 * - Total Trains
 * - Available Trains
 * - In Maintenance
 * - Km Variance (with traffic-light indicator)
 */
export function DashboardKPIs() {
  const router = useRouter();
  const [summary, setSummary] = useState<DashboardSummary | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchSummary() {
      setLoading(true);
      const { data, error } = await dashboardApi.getSummary();

      if (error) {
        setError(error);
      } else if (data) {
        setSummary(data);
      }
      setLoading(false);
    }

    fetchSummary();
  }, []);

  // Determine variance config based on status
  const getVarianceConfig = (status?: 'green' | 'yellow' | 'red'): {
    borderColor: 'variance-green' | 'variance-yellow' | 'variance-red' | 'primary';
    icon: IconName;
    subtitle: string;
  } => {
    switch (status) {
      case 'green':
        return {
          borderColor: 'variance-green',
          icon: 'tick-circle',
          subtitle: 'Target met',
        };
      case 'yellow':
        return {
          borderColor: 'variance-yellow',
          icon: 'warning-sign',
          subtitle: 'Attention needed',
        };
      case 'red':
        return {
          borderColor: 'variance-red',
          icon: 'error',
          subtitle: 'Critical variance',
        };
      default:
        return {
          borderColor: 'primary',
          icon: 'pulse',
          subtitle: '',
        };
    }
  };

  // Calculate available percentage
  const availablePercentage = summary
    ? Math.round((summary.availableTrains / summary.totalTrains) * 100)
    : 0;

  const varianceConfig = getVarianceConfig(summary?.varianceStatus);

  if (error) {
    return (
      <Callout intent={Intent.DANGER} title="Error loading dashboard">
        <p>{error}</p>
        <p style={{ marginTop: 8, fontSize: 12 }}>
          Make sure the API server is running at <code>http://localhost:4000</code>
        </p>
      </Callout>
    );
  }

  // Navigation handlers
  const handleNavigateFleet = () => router.push('/fleet');
  const handleNavigateAvailable = () => router.push('/fleet?status=fit');
  const handleNavigateMaintenance = () => router.push('/maintenance');
  const handleNavigateBalancing = () => router.push('/balancing');

  return (
    <div className="mms-grid-4">
      <KPICard
        title="Total Trains"
        value={summary?.totalTrains ?? '--'}
        borderColor="primary"
        icon="drive-time"
        loading={loading}
        onClick={handleNavigateFleet}
        tooltip="Click to view all trains"
      />
      <KPICard
        title="Available"
        value={summary ? `${summary.availableTrains}` : '--'}
        subtitle={summary ? `${availablePercentage}% of fleet` : undefined}
        borderColor="available"
        icon="tick-circle"
        loading={loading}
        onClick={handleNavigateAvailable}
        tooltip="Click to view available trains"
      />
      <KPICard
        title="In Maintenance"
        value={summary?.inMaintenanceCount ?? '--'}
        borderColor="maintenance"
        icon="build"
        loading={loading}
        onClick={handleNavigateMaintenance}
        tooltip="Click to view maintenance schedule"
      />
      <KPICard
        title="Km Variance"
        value={summary ? `${summary.kmVariance}%` : '--%'}
        subtitle={varianceConfig.subtitle}
        borderColor={varianceConfig.borderColor}
        icon={varianceConfig.icon}
        tooltip={summary ? `Fleet mileage variance: ${summary.kmVariance}% (target: ≤10%) - Click for details` : undefined}
        loading={loading}
        onClick={handleNavigateBalancing}
      />
    </div>
  );
}

