'use client';

import React from 'react';
import { Card, Elevation, Spinner, Icon, IconName } from '@blueprintjs/core';

interface KPICardProps {
  title: string;
  value: string | number;
  subtitle?: string;
  borderColor?: 'primary' | 'available' | 'maintenance' | 'variance-green' | 'variance-yellow' | 'variance-red';
  icon?: IconName;
  loading?: boolean;
  tooltip?: string;
  onClick?: () => void;
}

/**
 * KPI Card Component
 *
 * Displays a single KPI metric with title, value, and optional subtitle.
 * Uses EN 15380 railway terminology.
 */
export function KPICard({
  title,
  value,
  subtitle,
  borderColor = 'primary',
  icon,
  loading = false,
  tooltip,
  onClick,
}: KPICardProps) {
  const cardClassName = `mms-kpi-card ${borderColor}`;

  return (
    <Card
      elevation={Elevation.ONE}
      interactive={!!onClick}
      onClick={onClick}
      className={cardClassName}
      title={tooltip}
      style={{ padding: 'var(--mms-space-md)' }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <span style={{ fontSize: 'var(--mms-text-base)', fontWeight: 'var(--mms-font-medium)', color: 'var(--mms-text-secondary)' }}>{title}</span>
        {icon && <Icon icon={icon} size={20} color="var(--mms-text-secondary)" />}
      </div>
      <div style={{ marginTop: 'var(--mms-space-sm)' }}>
        {loading ? (
          <Spinner size={24} />
        ) : (
          <div style={{ fontSize: 'var(--mms-text-4xl)', fontWeight: 'var(--mms-font-bold)', color: 'var(--mms-text-primary)' }}>{value}</div>
        )}
      </div>
      {subtitle && !loading && (
        <div style={{ marginTop: 'var(--mms-space-xs)', fontSize: 'var(--mms-text-base)', color: 'var(--mms-text-secondary)' }}>{subtitle}</div>
      )}
    </Card>
  );
}

'use client';

import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import {
  Navbar,
  NavbarGroup,
  NavbarHeading,
  NavbarDivider,
  Button,
  Alignment,
  Tag,
  Intent,
  Tooltip,
} from '@blueprintjs/core';
import { useTheme } from './ThemeContext';

const navItems = [
  { href: '/', label: 'Dashboard', icon: 'dashboard' },
  { href: '/map', label: 'Map', icon: 'map' },
  { href: '/allocation', label: 'Allocation', icon: 'th-derived' },
  { href: '/fleet', label: 'Fleet', icon: 'drive-time' },
  { href: '/balancing', label: 'Balancing', icon: 'horizontal-bar-chart' },
  { href: '/schedule', label: 'Schedule', icon: 'timeline-events' },
  { href: '/maintenance', label: 'Maintenance', icon: 'build' },
];

/**
 * Main Navigation Component
 *
 * Provides navigation links to all main pages using Blueprint Navbar.
 * Highlights the current active page.
 * Includes theme toggle button for light/dark mode.
 */
export function Navigation() {
  const pathname = usePathname();
  const { theme, toggleTheme } = useTheme();

  return (
    <Navbar fixedToTop={false}>
      <NavbarGroup align={Alignment.LEFT}>
        <NavbarHeading>
          <Link href="/" style={{ textDecoration: 'none', color: 'inherit' }}>
            <strong style={{ color: 'var(--mms-primary)' }}>MMS</strong>
            <span style={{ marginLeft: 'var(--mms-space-sm)', fontSize: 'var(--mms-text-sm)', color: 'var(--mms-text-secondary)' }}>
              Metro Mileage Management
            </span>
          </Link>
        </NavbarHeading>
        <NavbarDivider />
        {navItems.map((item) => {
          const isActive = pathname === item.href ||
            (item.href !== '/' && pathname.startsWith(item.href));

          return (
            <Link key={item.href} href={item.href} style={{ textDecoration: 'none' }}>
              <Button
                minimal={!isActive}
                intent={isActive ? Intent.PRIMARY : Intent.NONE}
                text={item.label}
                icon={item.icon as any}
              />
            </Link>
          );
        })}
      </NavbarGroup>

      <NavbarGroup align={Alignment.RIGHT}>
        <Tooltip content={theme === 'light' ? 'Switch to Dark Mode' : 'Switch to Light Mode'}>
          <Button
            minimal
            icon={theme === 'light' ? 'moon' : 'flash'}
            onClick={toggleTheme}
            aria-label={theme === 'light' ? 'Switch to Dark Mode' : 'Switch to Light Mode'}
          />
        </Tooltip>
        <NavbarDivider />
        <Tag intent={Intent.WARNING} minimal>DEMO</Tag>
      </NavbarGroup>
    </Navbar>
  );
}

