'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Card, Elevation, Spinner, Callout, Intent, Tag, Button, Icon } from '@blueprintjs/core';
import { dashboardApi, MaintenanceAlertsResponse, MaintenanceAlert } from '@/lib/api';

// Maintenance type intents
const typeIntents: Record<string, Intent> = {
  PM1: Intent.SUCCESS,
  PM2: Intent.PRIMARY,
  HM: Intent.WARNING,
  OVH: Intent.DANGER,
};

// Maintenance type descriptions
const typeDescriptions: Record<string, string> = {
  PM1: 'Preventive Maintenance Level 1',
  PM2: 'Preventive Maintenance Level 2',
  HM: 'Heavy Maintenance',
  OVH: 'Overhaul',
};

interface AlertItemProps {
  alert: MaintenanceAlert;
  onClick?: () => void;
}

/**
 * Individual Alert Item
 */
function AlertItem({ alert, onClick }: AlertItemProps) {
  const formatDate = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-GB', {
      day: '2-digit',
      month: 'short',
    });
  };

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: 'var(--mms-space-sm) var(--mms-space-md)',
        cursor: 'pointer',
        borderBottom: '1px solid var(--mms-border-default)',
      }}
      onClick={onClick}
      role="button"
      tabIndex={0}
    >
      <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--mms-space-sm)' }}>
        <Tag
          intent={typeIntents[alert.type] || Intent.NONE}
          minimal
          title={typeDescriptions[alert.type]}
        >
          {alert.type}
        </Tag>
        <div>
          <div style={{ fontWeight: 'var(--mms-font-medium)', color: 'var(--mms-text-primary)' }}>{alert.trainId}</div>
          <div style={{ fontSize: 'var(--mms-text-sm)', color: 'var(--mms-text-secondary)' }}>
            {alert.depot} ({alert.depotCode})
          </div>
        </div>
      </div>
      <div style={{ textAlign: 'right' }}>
        <div style={{ fontSize: 'var(--mms-text-base)', fontWeight: 'var(--mms-font-medium)', color: 'var(--mms-text-primary)' }}>
          {formatDate(alert.date)}
        </div>
        <div style={{ fontSize: 'var(--mms-text-sm)', color: 'var(--mms-text-secondary)' }}>
          {alert.durationDays} {alert.durationDays === 1 ? 'day' : 'days'}
        </div>
      </div>
    </div>
  );
}

/**
 * Maintenance Alerts Component
 *
 * Displays upcoming maintenance events in the next 7 days
 * with counts by type and a list of upcoming events.
 */
export function MaintenanceAlerts() {
  const router = useRouter();
  const [data, setData] = useState<MaintenanceAlertsResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    async function fetchAlerts() {
      setLoading(true);
      const { data, error } = await dashboardApi.getMaintenanceAlerts();

      if (error) {
        setError(error);
      } else if (data) {
        setData(data);
      }
      setLoading(false);
    }

    fetchAlerts();
  }, []);

  const handleAlertClick = (_alertId: string) => {
    router.push('/maintenance');
  };

  const handleViewAll = () => {
    router.push('/maintenance');
  };

  if (loading) {
    return (
      <Card elevation={Elevation.ONE} style={{ padding: 'var(--mms-space-xl)', textAlign: 'center' }}>
        <Spinner size={32} />
      </Card>
    );
  }

  if (error) {
    return (
      <Callout intent={Intent.DANGER} title="Error loading maintenance alerts">
        {error}
      </Callout>
    );
  }

  if (!data || data.totalUpcoming === 0) {
    return (
      <Callout intent={Intent.SUCCESS} icon="tick-circle">
        No scheduled maintenance in the next 7 days
      </Callout>
    );
  }

  return (
    <Card elevation={Elevation.ONE} style={{ padding: 0, overflow: 'hidden' }}>
      {/* Summary Header */}
      <div style={{ padding: 'var(--mms-space-md)', borderBottom: '1px solid var(--mms-border-default)', backgroundColor: 'var(--mms-bg-surface)' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 'var(--mms-space-sm)' }}>
          <h3 style={{ margin: 0, fontSize: 'var(--mms-text-lg)', fontWeight: 'var(--mms-font-semibold)', color: 'var(--mms-text-primary)' }}>
            Upcoming Maintenance
          </h3>
          <span style={{ fontSize: 'var(--mms-text-base)', color: 'var(--mms-text-secondary)' }}>
            {data.totalUpcoming} event{data.totalUpcoming !== 1 ? 's' : ''} in next 7 days
          </span>
        </div>

        {/* Type Counts */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--mms-space-sm)' }}>
          {Object.entries(data.countByType).map(([type, count]) => (
            count > 0 && (
              <Tag
                key={type}
                intent={typeIntents[type] || Intent.NONE}
                minimal
                title={typeDescriptions[type]}
              >
                {type}: {count}
              </Tag>
            )
          ))}
        </div>
      </div>

      {/* Alerts List */}
      <div>
        {data.alerts.map((alert) => (
          <AlertItem
            key={alert.id}
            alert={alert}
            onClick={() => handleAlertClick(alert.id)}
          />
        ))}
      </div>

      {/* View All Link */}
      {data.totalUpcoming > 5 && (
        <div style={{ padding: 'var(--mms-space-sm)', backgroundColor: 'var(--mms-bg-surface)', textAlign: 'center' }}>
          <Button
            minimal
            intent={Intent.PRIMARY}
            rightIcon="arrow-right"
            onClick={handleViewAll}
          >
            View all {data.totalUpcoming} maintenance events
          </Button>
        </div>
      )}
    </Card>
  );
}

