'use client';

import React, { useEffect, useState, useCallback } from 'react';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  ReferenceLine,
  Cell,
} from 'recharts';
import { Card, Elevation, Spinner, Callout, Intent, Tag } from '@blueprintjs/core';
import { apiFetch } from '@/lib/api';

interface DistributionBucket {
  kmRange: string;
  count: number;
}

interface Outlier {
  trainId: string;
  currentKm: number;
  delta: number;
  deltaPercent: number;
  status: 'over' | 'under';
}

interface DistributionResponse {
  average: number;
  variance: number;
  distribution: DistributionBucket[];
  outliers: Outlier[];
}

interface RankedTrain {
  id: string;
  trainId: string;
  fleetName: string;
  depotCode: string;
  currentKm: number;
  targetKm: number;
  delta: number;
  deltaPercent: number;
  status: 'over' | 'under' | 'balanced';
}

interface RankingResponse {
  average: number;
  trains: RankedTrain[];
}

/**
 * Balancing Dashboard Component
 *
 * Displays mileage distribution, train ranking, and outlier identification.
 */
export function BalancingDashboard() {
  const [distribution, setDistribution] = useState<DistributionResponse | null>(null);
  const [ranking, setRanking] = useState<RankingResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);

    const [distRes, rankRes] = await Promise.all([
      apiFetch<DistributionResponse>('/api/balancing/distribution'),
      apiFetch<RankingResponse>('/api/balancing/ranking'),
    ]);

    if (distRes.error) {
      setError(distRes.error);
    } else {
      setDistribution(distRes.data);
    }

    if (rankRes.error && !error) {
      setError(rankRes.error);
    } else {
      setRanking(rankRes.data);
    }

    setLoading(false);
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', padding: 48 }}>
        <Spinner size={32} />
      </div>
    );
  }

