'use client';

import React, { useRef, useEffect, useCallback, useState } from 'react';
import { Application, Container, Graphics, Text, TextStyle } from 'pixi.js';
import { Viewport } from 'pixi-viewport';
import { Card, Elevation, Button } from '@blueprintjs/core';
import {
  LODLevel,
  getLODFromScale,
} from '@/stores/viewportStore';

interface MaintenanceEvent {
  id: string;
  trainId: string;
  trainName: string;
  type: 'PM1' | 'PM2' | 'HM' | 'OVH';
  startDate: Date;
  endDate: Date;
  depot: string;
}

interface ScheduleCanvasProps {
  events: MaintenanceEvent[];
  onEventSelect?: (event: MaintenanceEvent) => void;
  onEventHover?: (event: MaintenanceEvent | null) => void;
  startDate?: Date;
  endDate?: Date;
  width?: number;
  height?: number;
}

// Color palette for maintenance types
const MAINTENANCE_COLORS = {
  PM1: 0x10B981, // Green
  PM2: 0x3B82F6, // Blue
  HM: 0xF59E0B,  // Amber
  OVH: 0xEF4444, // Red
};

// LOD level descriptions
const LOD_LABELS = {
  0: 'Strategic (10-12 years)',
  1: 'Tactical (1-3 years)',
  2: 'Operational (1-6 months)',
  3: 'Execution (1-4 weeks)',
};

// Day width in pixels at scale 1.0
const DAY_WIDTH = 20;
const ROW_HEIGHT = 40;
const HEADER_HEIGHT = 60;

export function ScheduleCanvas({
  events,
  onEventSelect,
  onEventHover,
  startDate = new Date(),
  endDate = new Date(Date.now() + 365 * 24 * 60 * 60 * 1000),
  width = 1200,
  height = 600,
}: ScheduleCanvasProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const appRef = useRef<Application | null>(null);
  const viewportRef = useRef<Viewport | null>(null);

  // Use local state for LOD and scale to avoid toolkit infinite loop issue
  const [currentLOD, setCurrentLOD] = useState<LODLevel>(2);
  const [scale, setScale] = useState(0.5);

  // Initialize Pixi application
  useEffect(() => {
    if (!containerRef.current) return;

    const app = new Application();

    const initApp = async () => {
      await app.init({
        width,
        height,
        backgroundColor: 0x0A0A0A, // Dark canvas background
        resolution: window.devicePixelRatio || 1,
        autoDensity: true,
        antialias: true,
      });

      containerRef.current?.appendChild(app.canvas);
      appRef.current = app;

      // Create viewport
      const viewport = new Viewport({
        screenWidth: width,
        screenHeight: height,
        worldWidth: width * 10,
        worldHeight: height * 5,
        events: app.renderer.events,
      });

      app.stage.addChild(viewport);
      viewportRef.current = viewport;
